{
 "level": "B1–B2",
 "intro": "In this topic you will learn <strong>relative pronouns</strong> - words that connect sentences and give additional information.",
 "rules": [
 {
 "label": "WHO",
 "color": "emerald",
 "text": "<strong>Who</strong> — for people (subject/object):",
 "example": "The man who called is my boss."
 },
 {
 "label": "WHICH",
 "color": "blue",
 "text": "<strong>Which</strong> — for things and animals:",
 "example": "The book which I read was great."
 },
 {
 "label": "THAT",
 "color": "amber",
 "text": "<strong>That</strong> is universal (people/things):",
 "example": "The car that he bought is new."
 }
 ]
}

{
 "title": "1. Five Basic Relative Pronouns (things)",
 "intro": "Use the pattern in the examples and focus on the highlighted words.",
 "items": [
 {
 "label": "WHO",
 "title": "Who",
 "subtitle": "Grammar focus"
 },
 {
 "label": "WHICH",
 "title": "Which",
 "subtitle": "things and animals — The car which is red..."
 },
 {
 "label": "THAT",
 "title": "What/which (universal)",
 "subtitle": "people or things — The book that I read..."
 },
 {
 "label": "WHOSE",
 "title": "Whose (belonging)",
 "subtitle": "shows possession — The man whose car was stolen..."
 },
 {
 "label": "WHOM",
 "title": "Who (formally)",
 "subtitle": "object (formal language) — The person whom I met..."
 }
 ]
}

{
 "title": "2. WHO is for people",
 "sections": [
 {
 "label": "Who as subject",
 "color": "emerald",
 "description": "<strong>Who</strong> is used for people. Can be the <strong>subject</strong> in a relative clause.",
 "examples": [
 {
 "en": "The man who called is my boss.",
 "ua": "The man who called is my boss."
 },
 {
 "en": "The woman who lives here is a doctor.",
 "ua": "The woman who lives here is a doctor."
 },
 {
 "en": "People who exercise regularly are healthy. <strong>object</strong> (informal instead of whom).",
 "ua": "People who exercise regularly are healthy. <strong>object</strong> (informal instead of whom)."
 },
 {
 "en": "The teacher who taught me was excellent.",
 "ua": "The teacher who taught me was excellent."
 }
 ]
 },
 {
 "label": "Who as an object",
 "color": "sky",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "The man who I met was friendly.",
 "ua": "The man who I met was friendly."
 },
 {
 "en": "The person who you called is here.",
 "ua": "The person who you called is here."
 },
 {
 "en": "The woman who we saw yesterday was my neighbor. For animals and things — which or that.",
 "ua": "The woman who we saw yesterday was my neighbor. For animals and things — which or that."
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 },
 {
 "label": "Who is not for animals or things",
 "color": "purple",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "The dog who barks... (✗)",
 "ua": "The dog who barks... (✗)"
 },
 {
 "en": "The dog that/which barks... (✓)",
 "ua": "The dog that/which barks... (✓)"
 }
 ]
 }
 ]
}

{
 "title": "3. WHICH is for things and animals",
 "sections": [
 {
 "label": "Which is for things",
 "color": "blue",
 "description": "<strong>Which</strong> is used for things and animals (not for people).",
 "examples": [
 {
 "en": "The book which I read was great.",
 "ua": "The book which I read was great."
 },
 {
 "en": "The car which is red is mine.",
 "ua": "The car which is red is mine."
 },
 {
 "en": "The house which we bought is old.",
 "ua": "The house which we bought is old."
 },
 {
 "en": "The phone which I want costs a lot.",
 "ua": "The phone which I want costs a lot."
 }
 ]
 },
 {
 "label": "Which for animals",
 "color": "sky",
 "description": "Which also used for animals.",
 "examples": [
 {
 "en": "The dog which lives next door is friendly.",
 "ua": "The dog which lives next door is friendly."
 },
 {
 "en": "The cat which I saw was black.",
 "ua": "The cat which I saw was black."
 }
 ]
 },
 {
 "label": "Which for the whole sentence",
 "color": "purple",
 "description": "<strong>Which</strong> can refer to the entire previous phrase (with a comma!).",
 "examples": [
 {
 "en": "He passed the exam, which surprised everyone.",
 "ua": "He passed the exam, which surprised everyone."
 },
 {
 "en": "She arrived late, which made me angry.",
 "ua": "She arrived late, which made me angry."
 }
 ],
 "note": "📌 , which = reference to the whole situation."
 }
 ]
}

{
 "title": "4. THAT is a universal pronoun",
 "sections": [
 {
 "label": "That for people and things",
 "color": "amber",
 "description": "<strong>That</strong> is universal! Can be used instead of who or which (but not always!).",
 "examples": [
 {
 "en": "The man that called... = The man who called...",
 "ua": "The man that called... = The man who called..."
 },
 {
 "en": "The book that I read... = The book which I read...",
 "ua": "The book that I read... = The book which I read..."
 },
 {
 "en": "The car that he bought is new.",
 "ua": "The car that he bought is new."
 }
 ]
 },
 {
 "label": "When SHOULD you use that",
 "color": "emerald",
 "description": "After <strong>superlatives, all, every, only, first/last</strong> it is better to use that.",
 "examples": [
 {
 "en": "It's the best movie that I've ever seen.",
 "ua": "It's the best movie that I've ever seen."
 },
 {
 "en": "Everything that he said was true.",
 "ua": "Everything that he said was true."
 },
 {
 "en": "She's the only person that can help.",
 "ua": "She's the only person that can help."
 },
 {
 "en": "It's the first time that I've been here.",
 "ua": "It's the first time that I've been here."
 }
 ],
 "note": "📌 best, all, every, only, first → use that!"
 },
 {
 "label": "When NOT to use that",
 "color": "rose",
 "description": "That <strong>NOT</strong> can be used with a comma (non-defining clauses).",
 "examples": [
 {
 "en": "My brother, who lives in Kyiv, is a doctor. (✓)",
 "ua": "My brother, who lives in Kyiv, is a doctor. (✓)"
 },
 {
 "en": "My brother, that lives in Kyiv, is a doctor. (✗)",
 "ua": "My brother, that lives in Kyiv, is a doctor. (✗)"
 }
 ],
 "note": "📌 With a comma - only who/which, NOT that!"
 }
 ]
}

{
 "title": "5. WHOSE - whose (affiliation)",
 "sections": [
 {
 "label": "Whose shows ownership",
 "color": "purple",
 "description": "<strong>Whose</strong> (whose) shows affiliation. Used for people and things.",
 "examples": [
 {
 "en": "The man whose car was stolen called the police.",
 "ua": "The man whose car was stolen called the police."
 },
 {
 "en": "The woman whose daughter is a doctor lives here.",
 "ua": "The woman whose daughter is a doctor lives here."
 },
 {
 "en": "I know someone whose brother is famous.",
 "ua": "I know someone whose brother is famous."
 }
 ]
 },
 {
 "label": "Whose + noun",
 "color": "blue",
 "description": "<strong>whose</strong> always comes after <strong>noun. whose sister).",
 "examples": [
 {
 "en": "The boy whose bike was stolen... (✓)",
 "ua": "The boy whose bike was stolen... (✓)"
 },
 {
 "en": "The boy whose was stolen... (✗)",
 "ua": "The boy whose was stolen... (✗)"
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 },
 {
 "label": "Don't confuse whose with who's",
 "color": "amber",
 "description": "<strong>Whose</strong> (chis) ≠ <strong>who's</strong> (who is/has).",
 "examples": [
 {
 "en": "The man whose car... (possessive)",
 "ua": "The man whose car... (possessive)"
 },
 {
 "en": "The man who's calling... (who is)",
 "ua": "The man who's calling... (who is)"
 }
 ],
 "note": "📌 Whose = whose. Who's = who is."
 }
 ]
}

{
 "title": "6. WHOM is a formal language",
 "sections": [
 {
 "label": "Whom as an adjunct (formally)",
 "color": "sky",
 "description": "<strong>Whom</strong> is a formal variant of who as an adjunct. In colloquial speech, they usually use who.",
 "examples": [
 {
 "en": "The person whom I met was kind. (formal)",
 "ua": "The person whom I met was kind. (formal)"
 },
 {
 "en": "The person who I met was kind. (informal)",
 "ua": "The person who I met was kind. (informal)"
 }
 ]
 },
 {
 "label": "Whom after prepositions",
 "color": "purple",
 "description": "After prepositions (with, to, for) <strong>whom</strong> is formally used.",
 "examples": [
 {
 "en": "The person to whom I spoke... (formal)",
 "ua": "The person to whom I spoke... (formal)"
 },
 {
 "en": "The person who I spoke to... (informal)",
 "ua": "The person who I spoke to... (informal)"
 }
 ],
 "note": "📌 Whom is almost never used in colloquial speech."
 }
 ]
}

{
 "title": "7. Defining vs Non-defining clauses",
 "sections": [
 {
 "label": "Defining - without comma",
 "color": "emerald",
 "description": "<strong>Defining clauses</strong> - important information (without it, the sentence is unclear). Without com!",
 "examples": [
 {
 "en": "The man who called is my boss.",
 "ua": "The man who called is my boss."
 },
 {
 "en": "The book that I read was great.",
 "ua": "The book that I read was great."
 }
 ],
 "note": "📌 Defining = important information. Without com. You can that."
 },
 {
 "label": "Non-defining - with commas",
 "color": "blue",
 "description": "<strong>Non-defining clauses</strong> - additional information (can be removed). With commas!",
 "examples": [
 {
 "en": "My brother, who lives in Kyiv, is a doctor.",
 "ua": "My brother, who lives in Kyiv, is a doctor."
 },
 {
 "en": "London, which is the capital, is big.",
 "ua": "London, which is the capital, is big."
 }
 ],
 "note": "📌 Non-defining = additional information. With commas. Only who/which!"
 },
 {
 "label": "Key Differences",
 "color": "amber",
 "description": "Defining (without commas) is required information. Non-defining (with commas) is optional.",
 "examples": [
 {
 "en": "Students who work hard pass exams. (not all, only those who work)",
 "ua": "Students who work hard pass exams. (not all, only those who work)"
 },
 {
 "en": "My students, who work hard, pass exams. (all my students)",
 "ua": "My students, who work hard, pass exams. (all my students)"
 }
 ],
 "note": "Commas change the meaning of the sentence!"
 }
 ]
}

{
 "title": "8. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "That after a comma (non-defining).",
 "wrong": "My brother, that lives in Kyiv, is a doctor.",
 "right": "✅ <span class=\"font-mono\">My brother, who lives in Kyiv, is a doctor.</span>"
 },
 {
 "label": "Mistake 2",
 "color": "amber",
 "title": "Using who for things or animals.",
 "wrong": "The book who I read... / The dog who barks...",
 "right": "✅ <span class=\"font-mono\">The book that/which I read... / The dog that/which barks...</span>"
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Confusing whose and who's.",
 "wrong": "The man who's car was stolen... (who is car?)",
 "right": " ✅ <span class=\"font-mono\">The man whose car was stolen...</span>"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "Superfluous pronoun after relative pronoun.",
 "wrong": "The man who he called is my boss.",
 "right": " ✅ <span class=\"font-mono\">The man who called is my boss.</span>"
 }
 ]
}

{
 "title": "10. Practice",
 "select_title": "Exercise 1. Choose the correct pronoun",
 "select_intro": "Fill in the blanks with the correct relative pronoun.",
 "selects": [
 {
 "label": "The man ___ called is my boss. (who / which)",
 "prompt": "What pronoun?"
 },
 {
 "label": "The book ___ I read was great. (who / which)",
 "prompt": "What pronoun?"
 },
 {
 "label": "The woman ___ car was stolen... (whose / who)",
 "prompt": "What pronoun?"
 },
 {
 "label": "It's the best film ___ I've seen. (that / which)",
 "prompt": "Which pronoun?"
 },
 {
 "label": "My brother, ___ lives in Kyiv... (that / who)",
 "prompt": "Which pronoun?"
 }
 ],
 "options": [
 "who",
 "which",
 "that",
 "whose",
 "whom"
 ],
 "input_title": "Exercise 2. Fill in the blanks",
 "input_intro": "Write the correct relative pronoun.",
 "inputs": [
 {
 "before": "The woman ___ called is a doctor. (a woman who)",
 "after": "→"
 },
 {
 "before": "The car ___ I bought is new. (the car)",
 "after": "→"
 },
 {
 "before": "The man ___ dog is big... (the man whose dog)",
 "after": "→"
 },
 {
 "before": "Everything ___ he said was true. (all that)",
 "after": "→"
 }
 ],
 "rephrase_title": "Exercise 3. Correct the error",
 "rephrase_intro": "Find and correct the error with relative pronouns.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "The book who I read...",
 "example_target": "The book which/that I read..."
 },
 {
 "original": "1. My brother, that lives in Kyiv, is a doctor.",
 "placeholder": "Correct the error"
 },
 {
 "original": "2. The dog who barks is mine.",
 "placeholder": "Fix the error"
 },
 {
 "original": "3. The man who's car was stolen...",
 "placeholder": "Correct the error"
 }
 ]
}

